function displayComments(comments) {
  const commentDiv = document.getElementById('comments');
  if (commentDiv) {
    comments.forEach(comment => {
      const p = document.createElement('p');
      p.textContent = comment;
      commentDiv.appendChild(p);
    });
  }
}

